import { Hono } from 'hono';
import { z, ZodError } from 'zod';

const app = new Hono();

const TaskStatusSchema = z.enum(['todo', 'in_progress', 'done']);

app.put('/task/:id/status', async (c) => {
  const taskId = c.req.param('id');
  const status = c.req.query('status');

  try {
    // Validate the task ID and new status
    const parsedStatus = TaskStatusSchema.parse(status);

    // Simulate fetching the current status of the task from a database
    const currentStatus = await fetchTaskStatus(taskId);
    if (!currentStatus) {
      return c.json({ error: 'Task not found' }, 404);
    }

    // Validate the transition
    if (parsedStatus === 'todo' && currentStatus !== 'done') {
      return c.json({ error: 'Illegal transition from in_progress to todo' }, 422);
    } else if (parsedStatus === 'in_progress' && currentStatus !== 'todo') {
      return c.json({ error: 'Illegal transition from done to in_progress' }, 422);
    }

    // Update the task status
    await updateTaskStatus(taskId, parsedStatus);

    return c.json({ message: `Task ${taskId} status updated to ${parsedStatus}` });
  } catch (error) {
    if (error instanceof ZodError) {
      return c.json({ error: 'Invalid status' }, 400);
    }
    return c.json({ error: 'Internal server error' }, 500);
  }
});

async function fetchTaskStatus(taskId: string): Promise<string | null> {
  // Simulate fetching the task status from a database
  // Replace this with actual database logic
  const tasks = {
    '1': 'todo',
    '2': 'in_progress',
    '3': 'done'
  };
  return tasks[taskId] || null;
}

async function updateTaskStatus(taskId: string, status: string): Promise<void> {
  // Simulate updating the task status in a database
  // Replace this with actual database logic
  console.log(`Updating task ${taskId} status to ${status}`);
}

export default app;

